const price = parseFloat("{{unitPrice}}".replace("{{Symbol}}","").replaceAll(",","").trim());
const subProdPrice = parseFloat("{{subProdPrice}}".replace("{{Symbol}}","").replaceAll(",","").trim());
const signUpFee = parseFloat("{{signUpFee}}".replace("{{Symbol}}","").replaceAll(",","").trim());
const totalSignUpFee = parseFloat("{{totalSignUpFee}}".replace("{{Symbol}}","").replaceAll(",","").trim());
const subtotal = parseFloat("{{subtotalPrice}}".replace("{{Symbol}}","").replaceAll(",","").trim());
const total = parseFloat("{{total}}".replace("{{Symbol}}","").replaceAll(",","").trim());
const recurringSubtotal = parseFloat("{{recurringSubtotal}}".replace("{{Symbol}}","").replaceAll(",","").trim());
const recurringTotal = parseFloat("{{recurringTotal}}".replace("{{Symbol}}","").replaceAll(",","").trim());
let taxPrice
let recurringTax
if ('{{country}}' !== 'AU') {
    taxPrice = parseFloat("{{taxPrice}}".replace("{{Symbol}}","").replaceAll(",","").trim());
    recurringTax = parseFloat("{{recurringTax}}".replace("{{Symbol}}","").replaceAll(",","").trim());
} else {
    taxPrice = 0
    recurringTax = 0
}
let shippingPrice
if ('{{shippingPrice}}'.includes('Lettermail (untracked)') || '{{shippingPrice}}'.includes('Regular')) {
    shippingPrice = 0
} else {
    shippingPrice = parseFloat("{{shippingPrice}}".replace("{{Symbol}}","").replaceAll(",","").trim());

}
let recurringShipping
if ('{{recurringShipping}}'.includes('Free')) {
    recurringShipping = 0
} else {
    recurringShipping  = parseFloat("{{recurringShipping}}".replace("{{Symbol}}","").replaceAll(",","").trim());
}

const qty = {{qty}};
const subProdPrice2 = price * qty;
const totalSignUpFee2 = signUpFee * qty;
const subtotal2 = subProdPrice2 + totalSignUpFee2;
const total2 = parseFloat((subtotal2 + taxPrice + shippingPrice).toFixed(2))
const recurringTotal2 = parseFloat((recurringSubtotal + recurringTax + recurringShipping).toFixed(2))

return subProdPrice === subProdPrice2 
        && subtotal2 === subtotal 
        && total2 === total
        && subProdPrice2 === recurringSubtotal
        && recurringTotal2 === recurringTotal
